const { Manifold, CrossSection, label, setCircularSegments } = api;
setCircularSegments(48);

// Main tower body: cylinder r=7, h=26, centered at origin bottom at z=0
const towerBody = Manifold.cylinder(26, 7, 7, 48);

// Parapet ring at top (z=24..28), slightly wider r=7.5
const parapetRing = Manifold.cylinder(4, 7.5, 7.5, 48).translate([0, 0, 24]);

// Crenellations: cut rectangular notches from parapet top — 8 gaps
const numCrenels = 8;
const crenelW = 1.4;
const crenelH = 2.5;
const crenelZ = 25.5;
const radialInner = 3.0;
const radialOuter = 9.0;

let crenelCuts = [];
for (let i = 0; i < numCrenels; i++) {
  const angle = (i * 360) / numCrenels;
  const block = Manifold.cube([radialOuter - radialInner, crenelW, crenelH + 0.2])
    .translate([radialInner, -crenelW / 2, crenelZ - 0.1])
    .rotate([0, 0, angle]);
  crenelCuts.push(block);
}
const crenelUnion = Manifold.union(crenelCuts);
const stoneParts = towerBody.add(parapetRing).subtract(crenelUnion);

// Door opening on -Y face: arched recess carved into tower wall
// Dark door plate: placed behind front wall surface, overlapping 2 units into stone wall
// Extends from outside of tower inward for guaranteed union
const doorPlate = Manifold.cube([2.6, 2.5, 5.0]).translate([-1.3, -8.5, 0.1]);
// Arch cap — cylinder pressed into the wall
const archCap = Manifold.cylinder(2.5, 1.3, 1.3, 20).rotate([90, 0, 0]).translate([0, -8.5, 5.0]);
const doorFeature = doorPlate.add(archCap);

// Window recesses — thin dark plates extending from outer surface inward
const win1 = Manifold.cube([1.6, 2.5, 2.6]).translate([-0.8, -8.5, 10.0]);
const win2 = Manifold.cube([1.6, 2.5, 2.6]).translate([-0.8, -8.5, 16.0]);

// Conical roof: cone from r=6 at z=27 to tip at z=38
const roofCone = Manifold.cylinder(11, 6, 0, 48).translate([0, 0, 27]);

// Base disk wider than body for stability
const base = Manifold.cylinder(1.0, 8.5, 8.5, 48);

const stone = label(stoneParts.add(base), 'stone');
const roof = label(roofCone, 'roof');
const door = label(doorFeature, 'door');
const windows = label(win1.add(win2), 'windows');

return stone.add(roof).add(door).add(windows);
